module edge_counter(
    input               clk         ,
    input               rst_n       ,
    input               signal_in   ,

    output  reg [15:0]  count
);

    reg signal_out_q;

    // Register the input signal to detect rising edges
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            signal_out_q <= 0;
        end else begin
            signal_out_q <= signal_in;
        end
    end

    // Count rising edges
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            count <= 0;
        end else if (signal_in && !signal_out_q) begin
            count <= count + 1;
        end
    end

endmodule
